/*
 * round() test harness -- prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly round  (test_round_opt.elf)
 *   2. Linked with toolchain's default round        (test_round_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile double g_acc;
#endif

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += round(vx);
#else
    double r = round(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* test_representative_100: 100 hand-picked inputs                    */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(DBL_MIN);                             /* 2^-1022, smallest normal positive */
    emit(-DBL_MIN);                            /* smallest normal negative */
    emit_u(0x0010000000000001ULL);             /* one ULP above DBL_MIN */
    emit(DBL_MAX);                             /* 0x7fefffffffffffff, largest finite positive */
    emit(-DBL_MAX);                            /* largest finite negative */
    emit_u(0x7fefffffffffffffULL);             /* one ULP below DBL_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0x3feffffffffffffe ULL); /* a few ULPs below 1.0 */
    emit_u(0x3ff0000000000002ULL);  /* a few ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3fdffffffffffffeULL);  /* one ULP below 0.5 */
    emit(0.5);
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */
    emit(2.0);
    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */

    /* --- Section 6: Half-integer tie-breaking values (14) --- */
    /* round() rounds away from zero at 0.5: 0.5->1, -0.5->-1 */
    emit(0.5);   /* already in sec 5, but keeping count: counted above */
    emit(1.5);
    emit(2.5);
    emit(3.5);
    emit(4.5);
    emit(5.5);
    emit(6.5);
    emit(-0.5);
    emit(-1.5);
    emit(-2.5);
    emit(-3.5);
    emit(-4.5);
    emit(-5.5);
    emit(-6.5);

    /* --- Section 7: ULP neighbors of key tie-breaking boundary 0.5 (8) --- */
    /* These stress the round-at-exactly-0.5 path */
    emit_u(0x3fe0000000000000ULL);  /* exactly 0.5 (same as emit(0.5)) */
    emit_u(0x3fdffffffffffffeULL);  /* 2 ULP below 0.5 */
    emit_u(0x3fe0000000000002ULL);  /* 2 ULP above 0.5 */
    emit_u(0xbfe0000000000000ULL);  /* exactly -0.5 */
    emit_u(0xbfdffffffffffffeULL);  /* 2 ULP toward zero from -0.5 */
    emit_u(0xbfe0000000000002ULL);  /* 2 ULP away from zero from -0.5 */
    emit_u(0x3fe0000000000000ULL - 1); /* 1 ULP below 0.5 (0x3fdffffffffffff) */
    emit_u(0xbfe0000000000000ULL - 1); /* 1 ULP toward zero from -0.5 */

    /* --- Section 8: Fractional values covering [0,2) (10) --- */
    emit(0.1);
    emit(0.25);
    emit(0.4);
    emit(0.75);
    emit(0.9);
    emit(1.1);
    emit(1.4);
    emit(1.6);
    emit(1.9);
    emit(2.4);

    /* --- Section 9: Large values where double has no fractional part (10) --- */
    /* 2^52 = 4503599627370496 -- at this magnitude doubles represent integers */
    emit_u(0x4330000000000000ULL);  /* 2^52 exactly: no fractional bits */
    emit_u(0x4330000000000001ULL);  /* 2^52 + 1 ULP */
    emit_u(0xb330000000000000ULL);  /* -2^52 exactly */
    emit_u(0x4340000000000000ULL);  /* 2^53 exactly */
    emit_u(0xb340000000000000ULL);  /* -2^53 exactly */
    emit(1.0e15);                   /* large but still has fractional resolution */
    emit(-1.0e15);
    emit(1.0e16);                   /* 10^16: near limit of fractional resolution */
    emit(-1.0e16);
    emit(1.0e18);                   /* 10^18: well above 2^53, all-integer */

    /* --- Section 10: Additional integer, negative, and boundary cases (25) --- */
    /* Small positive integers */
    emit(1.0);
    emit(2.0);
    emit(3.0);
    emit(4.0);
    emit(5.0);
    /* Small negative integers */
    emit(-1.0);
    emit(-2.0);
    emit(-3.0);
    emit(-4.0);
    emit(-5.0);
    /* Negative fractional values */
    emit(-0.1);
    emit(-0.25);
    emit(-0.4);
    emit(-0.75);
    emit(-0.9);
    emit(-1.1);
    emit(-1.6);
    emit(-2.4);
    /* Near large power-of-2 boundaries with fractional part */
    emit_u(0x4170000000000000ULL);  /* 2^24 = 16777216: smallest power-of-2 with no fractional float-range ULPs */
    emit_u(0x4170000000000001ULL);  /* 2^24 + 1 ULP */
    emit_u(0x41b0000000000000ULL);  /* 2^28 = 268435456 */
    emit_u(0x41d0000000000000ULL);  /* 2^30 = 1073741824 */
    /* Values just above/below integer at exponent 2 */
    emit_u(0x400fffffffffffffULL);  /* one ULP below 4.0 (= 3.9999...) */
    emit_u(0x4010000000000001ULL);  /* one ULP above 4.0 */
}

/* ------------------------------------------------------------------ */
/* Dense sweep (accuracy path only)                                   */
/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* Sweep [0, 10] in 100 steps and [-10, 0] in 100 steps */
static void test_sweep(void)
{
    double hi = 10.0;
    int nsteps = 100;
    double step = hi / (double)nsteps;

    /* [0, 10] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* [-10, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* Sample [0, 10] every ~0.05 (200 points) */
static void test_exhaustive_small(void)
{
    double hi = 10.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

